<template>
  <div>
    <v-navigation-drawer
      dir="ltr"
      :clipped="clipped"
      v-model="drawer"
      nable-resize-watcher
      app
      right
      class="navigation-drawer"
    >
      <v-list-item>
        <template v-slot:prepend>
          <Icon icon="tdesign:system-sum" color="white" width="50" />
        </template>

        <v-list-item-title
          ><h2 class="text-center mt-4 mb-4 py-3" style="color: white">
            نظام سداد
          </h2></v-list-item-title
        >
      </v-list-item>

      <v-divider></v-divider>

      <v-list nav>
        <v-list-item
          v-for="(opation, index) in opations"
          :key="index"
          :to="opation.link"
          @click="model = index"
          :class="model == index ? 'list-item' : ''"
          class="list-itemAll"
          lines="two"
        >
          <v-list-item-title class="d-flex justify-end mr-2 py-3">
            <h2
              :class="
                model == index ? 'color-icon-title-D' : 'color-icon-title-A'
              "
            >
              {{ opation.title }}
            </h2>
          </v-list-item-title>

          <template v-slot:prepend>
            <Icon
              :icon="opation.icon"
              :class="
                model == index ? 'color-icon-title-D' : 'color-icon-title-A'
              "
              width="30"
            />
          </template>
        </v-list-item>
      </v-list>
      <template v-slot:append>
        <div class="d-flex justify-center">
          <v-btn
            class="btn-logout"
            size="x-large"
            color="white"
            variant="outlined"
          >
            <h4>تسجيل خروج</h4>
            <Icon icon="majesticons:logout-line" color="white" width="32" />
          </v-btn>
        </div>
      </template>
    </v-navigation-drawer>
  </div>
</template>
<script setup>
import { ref, onMounted, watch } from "vue";
const drawer = ref(true);
const model = ref(0);
const clipped = ref(false);
const STORAGE_KEY = "sidebar-selected-index";

const opations = ref([
  {
    title: "الاحصائيات",
    icon: "solar:pie-chart-2-bold",
    link: "statistics",
  },
  {
    title: "المنتجات",
    icon: "solar:box-bold",
    link: "goods",
  },
  {
    title: "نقطة البيع",
    icon: "solar:cart-large-bold",
    link: "/",
  },
  {
    title: "مبيعات النقد",
    icon: "solar:clipboard-list-bold",
    link: "sales",
  },
  {
    title: "مبيعات الآجل",
    icon: "lucide:clipboard-clock",
    link: "debits",
  },
  {
    title: "التوصيل",
    icon: "material-symbols:delivery-truck-speed-rounded",
    link: "sales-delivery",
  },
]);

// Load from localStorage when component mounts
onMounted(() => {
  const savedModel = localStorage.getItem(STORAGE_KEY);
  if (savedModel !== null) {
    model.value = parseInt(savedModel);
  }
});

// Save to localStorage whenever model changes
watch(model, (newVal) => {
  localStorage.setItem(STORAGE_KEY, newVal);
});
</script>

<style scoped>
.btn-logout {
  margin-bottom: 30px;
  border-radius: 15px !important;
}
.navigation-drawer {
  background: linear-gradient(180deg, #624fc6 0%, #090040 99%);
}
.v-list-item:before {
  border-radius: 15px !important;
  background: rgb(185, 237, 221) !important;
  opacity: 0;
}

.list-item {
  border-radius: 15px !important;
  background: #1f2544 !important;
}
.list-itemAll:hover {
  border-radius: 15px !important;
  background: #1f2544 !important;
}
.color-icon-title-A {
  color: rgb(255, 255, 255, 0.8);
}
.color-icon-title-D {
  color: rgb(255, 255, 255);
}
.type_zero {
  margin-top: 450px;
}
</style>
