import { createRouter, createWebHistory } from "vue-router";
import Statistics from "../views/Statistics.vue";
import Goods from "../views/Goods.vue";
import Sales from "../views/Sales.vue";
import Debits from "../views/Debits.vue";
import SalesPoint from "../views/SalesPoint.vue";
import SalesDelivery from "../views/SalesDelivery.vue";
import Login from "../views/Login.vue";
const routes = [
 {
    path: "/statistics",
    name: "statistics",
    component: Statistics,
    beforeEnter: loggedIn,
  },
  {
    path: "/goods",
    name: "goods",
    component: Goods,
    beforeEnter: loggedIn,
  },
  {
    path: "/",
    name: "home",
    component: SalesPoint,
    beforeEnter: loggedIn,
  },
  {
    path: "/sales-delivery",
    name: "sales-delivery",
    component: SalesDelivery,
    beforeEnter: loggedIn,
  },
  {
    path: "/sales",
    name: "sales",
    component: Sales,
    beforeEnter: loggedIn,
  },
  {
    path: "/debits",
    name: "debits",
    component: Debits,
    beforeEnter: loggedIn,
  },
  {
    path: "/login",
    name: "login",
    component: Login,
    beforeEnter: redirect,
  },
];

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes,
});

export default router;

function loggedIn(to, from, next) {
  const token = localStorage.getItem("token");
  if (token) {
    next();
  } else {
    next("/login");
  }
}

function redirect(to, from, next) {
  const token = localStorage.getItem("token");
  if (token) {
    next("/");
  } else {
    next();
  }
}
