<template>
  <div id="invoice" ref="invoiceRef" :class="['receipt', paperSize]">
    <div class="header head mx-auto">
      <h3>{{ nameStore }}</h3>
      <p>إيصال مبيعات - Sales Receipt</p>
      <p>{{ formattedDate }}</p>
      <hr />
    </div>

    <table>
      <thead>
        <tr>
          <th>المنتج<br />Product</th>
          <th>القياس<br />Size</th>
          <th>الكمية<br />Qty</th>
          <th>السعر<br />Price</th>
          <th>الإجمالي<br />Total</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="(item, index) in purchasedItems" :key="index">
         <td><div class="product-name">{{ item.product_name }}</div></td>

          <td>{{ item.size }}</td>
          <td>
            {{ item.quantity - (item.returned_quantity || 0) }}
            <span
              v-if="item.returned_quantity > 0"
             class="returned-text"
            >
              (راجع: {{ item.returned_quantity }})
            </span>
          </td>
          <td>{{ formatNumber(item.price) }}</td>
          <td>
            {{
              formatNumber(
                item.price * (item.quantity - (item.returned_quantity || 0))
              )
            }}
          </td>
        </tr>
      </tbody>
    </table>

    <hr />

    <div class="totals">
      <p>
        <strong>المجموع الكلي - </strong>
        {{ formatNumber(adjustedTotalPrice) }} د.ع
      </p>
    </div>

    <span class="d-flex justify-center totals" v-if="saleType == 1 || saleType == 2">
      <strong>  نوع الشراء  </strong> 
      <span class="px-2"> - </span>
      <span v-if="saleType == 1"> آجل </span>
      <span v-else-if="saleType == 2">  توصيل </span>
    </span>

    <p v-if="hasReturns()" class="returns-note">
      (ملاحظة: تم خصم العناصر المسترجعة من الفاتورة)
    </p>

    <hr />
    <!-- هنا نضيف الباركود في النهاية -->
    <div class="barcode-container">
      <canvas ref="barcodeCanvas"></canvas>
    </div>
    <hr />

    <div class="footer">
      <p>شكراً لتسوقكم معنا! - Thank you!</p>
    </div>
  </div>
</template>

<script setup>
import moment from "moment-timezone";

import JsBarcode from "jsbarcode";
import { ref, onMounted, watch, computed,nextTick } from "vue";

const emit = defineEmits(["ready"]); // 👈 جديد

const props = defineProps({
  purchasedItems: {
    type: Array,
    default: null,
  },
  paperSize: {
    type: String,
    default: "size-58", // 'size-58' or 'size-80'
  },
  nameStore: {
    type: String,
    default: "",
  },
  saleType: {
    type: Number,
    required: true,
  },
  invoiceId: {
    type: String,
    required: true,
  },
  date: {
    type: String,
    required: true,
  },
});

// تنسيق التاريخ حسب توقيت بغداد
const formattedDate = moment(props.date)
  .tz("Asia/Baghdad")
  .format("YYYY-MM-DD hh:mm A");

function formatNumber(number) {
  return new Intl.NumberFormat("en-IQ", { maximumFractionDigits: 2 }).format(
    number
  );
}

const barcodeCanvas = ref(null);

const hasReturns = () => {
  return props.purchasedItems.some((item) => (item.returned_quantity || 0) > 0);
};

const generateBarcode = (value) => {
  if (!barcodeCanvas.value) return;
  JsBarcode(barcodeCanvas.value, value, {
    format: "code128",
    lineColor: "#000",
    width: 1.5, // صغّر عرض الخط قليلاً
    height: 40, // قلل الارتفاع
    margin: 5, // حدد المسافة الفارغة حول الباركود
    displayValue: true,
    fontSize: 12,
  });
};

const adjustedTotalPrice = computed(() => {
  return props.purchasedItems.reduce((acc, item) => {
    const soldQty = item.quantity - (item.returned_quantity || 0);
    return acc + item.price * soldQty;
  }, 0);
});


let emitted = false;

onMounted(async () => {
  generateBarcode(props.invoiceId);
  await nextTick();
  if (!emitted) { emitted = true; requestAnimationFrame(() => emit("ready")); }
});

watch(() => props.invoiceId, async (id) => {
  generateBarcode(id);
  await nextTick();
  if (!emitted) { emitted = true; requestAnimationFrame(() => emit("ready")); }
});

</script>

<style scoped>
.receipt {
  font-family: monospace, "Tahoma", "Arial";
  font-size: 12.5px; /* تقليل طفيف ليتسع الاسم */
  direction: rtl;
  margin: auto;
  border: 1px dashed #aaa;
  padding: 4px;
  color: #000;
  background: #fff;
  box-sizing: border-box;
}

.header,
.footer {
  text-align: center;
  font-family: monospace, "Tahoma", "Arial";
}

/* حاوية الباركود */
.barcode-container {
  text-align: center;
  margin-top: 8px;
  margin-bottom: 8px;
}
canvas { max-width: 100%; width: 200px; height: auto; }

/* عرض الورقة حسب النوع (عرض ثابت بالمليمتر) */
.size-58 { width: 58mm; max-width: 58mm; }
.size-80 { width: 80mm; max-width: 80mm; }

.head { margin-bottom: 12px !important; }

/* جدول الفاتورة */
table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed; /* نحافظ على القيم المحددة للأعمدة */
  font-family: monospace, "Tahoma", "Arial";
}

/* رؤوس الأعمدة */
thead th {
  border-bottom: 1px solid #000;
  font-weight: bold;
  font-size: 10px;
  padding: 2px 4px;
  text-align: center;
  box-sizing: border-box;
}

/* خلي الخلايا تغلف النص بشكل آمن */
td, th {
  box-sizing: border-box;
  padding: 2px 4px;
  vertical-align: top;
}

/* نطبق قواعد محسّنة لعمود اسم المنتج */
.product-name {
  white-space: normal;
  overflow-wrap: anywhere;    /* يكسر الكلمات الطويلة إذا لزم */
  word-break: break-word;
  display: block;
  text-align: right;
  line-height: 1.1;
  font-size: 12px;
}

/* محاذاة عامة للخلايا */
tbody td { text-align: center; font-size: 11px; }

/* --------------------------------------------------
   عرض أعمدة دقيق حسب عرض الورق (بالـ mm) لتجنب القص
   -------------------------------------------------- */

/* إعداد لأوراق 80mm */
.size-80 thead th:nth-child(1),
.size-80 tbody td:nth-child(1) { width: 20mm; } /* Product */
.size-80 thead th:nth-child(2),
.size-80 tbody td:nth-child(2) { width: 10mm; } /* Size */
.size-80 thead th:nth-child(3),
.size-80 tbody td:nth-child(3) { width: 8mm;  } /* Qty */
.size-80 thead th:nth-child(4),
.size-80 tbody td:nth-child(4) { width: 13mm; } /* Price */
.size-80 thead th:nth-child(5),
.size-80 tbody td:nth-child(5) { width: 13mm; } /* Total */

/* إعداد لأوراق 58mm */
.size-58 thead th:nth-child(1),
.size-58 tbody td:nth-child(1) { width: 20mm; } /* Product */
.size-58 thead th:nth-child(2),
.size-58 tbody td:nth-child(2) { width: 8mm;  } /* Size */
.size-58 thead th:nth-child(3),
.size-58 tbody td:nth-child(3) { width: 6mm;  } /* Qty */
.size-58 thead th:nth-child(4),
.size-58 tbody td:nth-child(4) { width: 9mm;  } /* Price */
.size-58 thead th:nth-child(5),
.size-58 tbody td:nth-child(5) { width: 9mm;  } /* Total */

/* تأكد من محاذاة عمود المنتج لليمين (RTL) */
thead th:nth-child(1),
tbody td:nth-child(1) {
  text-align: right;
}

/* نص المرتجع */
.returned-text {
  font-size: 11px;
  font-weight: bold;
  text-decoration: underline;
  color: #000;
  display: block;
  margin-top: 2px;
}

/* مظهر المجموع */
.totals { text-align: center; font-size: 12px; font-weight: bold; margin-top: 6px; }

/* hr */
hr { border-top: 1px dashed #000; margin: 6px 0; }

</style>

<style>
/* في نفس ملف الفاتورة أو global.css */

@media print {
  /* اخفِ كل أبناء الـ body ما عدا حاوية الطباعة */
  body > *:not(#print-root) {
    display: none !important;
  }

  /* أظهر حاوية الطباعة ومحتواها فقط */
  #print-root {
    display: block !important;
  }

  /* إعدادات الصفحة الحرارية */
  @page {
    size: 80mm auto;  /* الطول تلقائي حسب المحتوى */
    margin: 0mm;
  }


  /* لمنع انقسام الفاتورة */
  #invoice { page-break-inside: avoid;  
    width: 80mm !important;  /* تأكيد الامتداد */
    max-width: 80mm !important;
    margin: 0 auto;
    transform: none !important;
    position: static !important;
  }
}

</style>
